import{_ as i,o as a,c as l,a2 as o}from"./chunks/framework.VshInwhI.js";const u=JSON.parse('{"title":"前端测试规范","description":"","frontmatter":{},"headers":[],"relativePath":"mango-pmo/rules/frontend/04-test.md","filePath":"mango-pmo/rules/frontend/04-test.md"}'),t={name:"mango-pmo/rules/frontend/04-test.md"};function s(d,e,c,r,n,p){return a(),l("div",null,[...e[0]||(e[0]=[o(`<h1 id="前端测试规范" tabindex="-1">前端测试规范 <a class="header-anchor" href="#前端测试规范" aria-label="Permalink to &quot;前端测试规范&quot;">​</a></h1><h2 id="_1-基本要求" tabindex="-1">1. 基本要求 <a class="header-anchor" href="#_1-基本要求" aria-label="Permalink to &quot;1. 基本要求&quot;">​</a></h2><ul><li>有前端改动，必须有对应验证。</li><li>新增交互，必须覆盖主要流程。</li><li>修复缺陷，必须补回归验证。</li><li>测试用例登记、自动化层级、执行策略、稳定锚点和结果基线遵循 <code>rules/09-test-case-automation-flow.md</code>。</li></ul><h2 id="_2-测试层次" tabindex="-1">2. 测试层次 <a class="header-anchor" href="#_2-测试层次" aria-label="Permalink to &quot;2. 测试层次&quot;">​</a></h2><ul><li>单元测试：工具函数、组合式函数、独立逻辑。</li><li>组件测试：组件渲染、输入输出、事件。</li><li>E2E 测试：页面主流程、路由、接口联动。</li><li>是否需要视觉截图，按改动影响面决定。</li></ul><h2 id="_3-页面回归走查" tabindex="-1">3. 页面回归走查 <a class="header-anchor" href="#_3-页面回归走查" aria-label="Permalink to &quot;3. 页面回归走查&quot;">​</a></h2><p>涉及页面、菜单、路由、样式、组件集成、微前端、运行时配置或打包方式的改动，必须做页面细节走查。</p><p>必须检查：</p><ul><li>截图留存：每个关键页面至少保留一张截图，截图路径写入交付记录。</li><li>页面内容：不能只验证 URL 打开；必须确认主内容区域有业务内容，不是空白、404、加载失败或无限 loading。</li><li>框架区域：左侧菜单、顶部栏、面包屑、用户区、通知入口和当前菜单激活状态符合预期。</li><li>样式细节：按钮、图标、表格、表单、弹窗、卡片、工具栏位置和形状不能明显跑偏。</li><li>交互细节：搜索、新增、编辑、提交、弹窗打开关闭、页签或菜单切换等关键动作至少覆盖主路径。</li><li>数据状态：正常数据、空状态、接口错误或权限不足必须有明确页面反馈。</li><li>控制台与网络：记录 console error、Vue error、资源 404、接口 4xx/5xx；存在错误时不得声明页面通过。</li><li>部署形态：单体和微前端共用页面、组件或样式时，必须分别验证对应形态。</li></ul><p>禁止把“服务已启动”“路由可访问”“截图有画面”当作页面验收通过。交付结论必须写明具体页面、关键元素、异常记录和截图路径。</p><h2 id="_3-1-有效-e2e-验收" tabindex="-1">3.1 有效 E2E 验收 <a class="header-anchor" href="#_3-1-有效-e2e-验收" aria-label="Permalink to &quot;3.1 有效 E2E 验收&quot;">​</a></h2><p>E2E 验收必须验证用户可见结果和业务结果，不能只验证接口 200 或没有前端异常。</p><p>每个关键功能点至少记录：</p><ul><li>页面路径和菜单入口。</li><li>操作步骤和测试数据。</li><li>接口请求结果，以及页面是否按接口数据正确回显。</li><li>业务结果断言，例如列表新增一行、详情字段更新、状态标签变化、分页总数变化、按钮禁用或弹窗关闭。</li><li>UI 细节断言，例如主按钮位置、表格列、表单分组、必填校验、错误提示、加载态、空状态和权限不足提示。</li><li>console error、Vue error、资源 404、接口 4xx/5xx 检查结果。</li><li>截图或 trace/video 路径。</li></ul><p>涉及新增、编辑、删除、启停、导入、导出、审批、上传、下载、搜索、重置、分页、批量操作时，台账必须逐项列出对应功能点和证据。</p><p>前端 E2E 脚本必须按业务语义定位，优先使用 <code>data-page</code>、<code>data-surface</code>、<code>data-action</code>、<code>data-field</code>、<code>data-record-key</code> 和 <code>data-state</code>。<code>specs</code> 中禁止直接依赖 Element Plus 内部 class、布局 class、深层 DOM、字段顺序、<code>nth()</code>、<code>waitForTimeout()</code> 或 <code>force: true</code>；无法避免时只能封装在 <code>support</code>、<code>fixtures</code>、<code>tasks</code> 或 <code>components</code> 中，并写明原因。</p><p>前端 E2E 用例必须按 <code>@p0</code>、<code>@p1</code>、<code>@p2</code> 和模块标签分级。PR 和 AI 交付优先执行相关 <code>@p0</code>，主干定时执行 <code>@p0/@p1</code>，夜间或发布前执行 <code>@p2</code>。</p><p>验收证据必须使用 <code>mango-pmo/templates/acceptance-evidence.md</code> 或同结构表格记录，并在交付前执行：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">node</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> mango-pmo/tools/acceptance-evidence-check.mjs</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --evidence</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">验收证据文件路</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">径</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span></span></code></pre></div><p>以下结论无效：</p><ul><li>“接口返回 200，功能通过。”</li><li>“页面打开无报错，功能通过。”</li><li>“截图正常，功能通过。”</li><li>“主流程跑通，其他场景未测。”</li></ul><h2 id="_4-测试范围" tabindex="-1">4. 测试范围 <a class="header-anchor" href="#_4-测试范围" aria-label="Permalink to &quot;4. 测试范围&quot;">​</a></h2><p>至少覆盖：</p><ul><li>正常场景</li><li>空状态</li><li>错误场景</li><li>关键交互</li><li>权限或路由限制</li></ul><h2 id="_5-命名规则" tabindex="-1">5. 命名规则 <a class="header-anchor" href="#_5-命名规则" aria-label="Permalink to &quot;5. 命名规则&quot;">​</a></h2><ul><li>测试资产目录归属遵循 <code>mango-pmo/rules/04-test-assets.md</code>。</li><li>测试文件使用 <code>*.spec.ts</code> 或 <code>*.test.ts</code>。</li><li>用例名称直接描述场景和结果。</li></ul><h2 id="_6-提交前检查" tabindex="-1">6. 提交前检查 <a class="header-anchor" href="#_6-提交前检查" aria-label="Permalink to &quot;6. 提交前检查&quot;">​</a></h2><p>至少执行与改动范围对应的检查：</p><ul><li><code>pnpm test</code></li><li><code>pnpm build</code></li><li><code>pnpm playwright test</code></li></ul><h2 id="_7-禁止事项" tabindex="-1">7. 禁止事项 <a class="header-anchor" href="#_7-禁止事项" aria-label="Permalink to &quot;7. 禁止事项&quot;">​</a></h2><ul><li>页面改动没有任何验证</li><li>只测 happy path</li><li>发现回归后不补测试</li><li>没有截图和页面细节结论就声明页面通过</li></ul>`,31)])])}const m=i(t,[["render",s]]);export{u as __pageData,m as default};
